package com.bankingapp;

import android.app.Activity;
import android.content.Context;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.EditText;
import android.widget.TextView;
import android.widget.Toast;
import java.io.BufferedReader;
import java.io.InputStreamReader;
import java.io.OutputStream;
import java.net.HttpURLConnection;
import java.net.URL;
import org.json.JSONObject;

public class BankingActivity extends Activity {
    
    private EditText accountNumberInput;
    private EditText amountInput;
    private EditText recipientAccountInput;
    private TextView balanceDisplay;
    private Button transferButton;
    private Button checkBalanceButton;
    private SharedPreferences prefs;
    
    private static final String API_BASE_URL = "http://api.bankingserver.com";
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking);
        
        prefs = getSharedPreferences("BankingPrefs", Context.MODE_WORLD_READABLE);
        
        accountNumberInput = findViewById(R.id.accountNumber);
        amountInput = findViewById(R.id.amount);
        recipientAccountInput = findViewById(R.id.recipientAccount);
        balanceDisplay = findViewById(R.id.balanceDisplay);
        transferButton = findViewById(R.id.transferButton);
        checkBalanceButton = findViewById(R.id.checkBalanceButton);
        
        checkBalanceButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                checkBalance();
            }
        });
        
        transferButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processTransfer();
            }
        });
    }
    
    private void checkBalance() {
        new Thread(new Runnable() {
            @Override
            public void run() {
                try {
                    String accountNumber = accountNumberInput.getText().toString();
                    String pin = prefs.getString("user_pin", "");
                    
                    String urlString = API_BASE_URL + "/balance?account=" + accountNumber + "&pin=" + pin;
                    URL url = new URL(urlString);
                    HttpURLConnection conn = (HttpURLConnection) url.openConnection();
                    conn.setRequestMethod("GET");
                    
                    BufferedReader reader = new BufferedReader(new InputStreamReader(conn.getInputStream()));
                    StringBuilder response = new StringBuilder();
                    String line;
                    while ((line = reader.readLine()) != null) {
                        response.append(line);
                    }
                    reader.close();
                    
                    JSONObject jsonResponse = new JSONObject(response.toString());
                    final String balance = jsonResponse.getString("balance");
                    
                    runOnUiThread(new Runnable() {
                        @Override
                        public void run() {
                            balanceDisplay.setText("Balance: $" + balance);
                        }
                    });
                    
                } catch (Exception e) {
                    e.printStackTrace();
                }
            }
        }).start();
    }
    
    private void processTransfer() {
        new Thread(new Runnable() {
            @Override
            public void run() {
                try {
                    String fromAccount = accountNumberInput.getText().toString();
                    String toAccount = recipientAccountInput.getText().toString();
                    String amount = amountInput.getText().toString();
                    String pin = prefs.getString("user_pin", "");
                    
                    JSONObject requestData = new JSONObject();
                    requestData.put("from_account", fromAccount);
                    requestData.put("to_account", toAccount);
                    requestData.put("amount", amount);
                    requestData.put("pin", pin);
                    
                    URL url = new URL(API_BASE_URL + "/transfer");
                    HttpURLConnection conn = (HttpURLConnection) url.openConnection();
                    conn.setRequestMethod("POST");
                    conn.setRequestProperty("Content-Type", "application/json");
                    conn.setDoOutput(true);
                    
                    OutputStream os = conn.getOutputStream();
                    os.write(requestData.toString().getBytes());
                    os.flush();
                    os.close();
                    
                    BufferedReader reader = new BufferedReader(new InputStreamReader(conn.getInputStream()));
                    StringBuilder response = new StringBuilder();
                    String line;
                    while ((line = reader.readLine()) != null) {
                        response.append(line);
                    }
                    reader.close();
                    
                    JSONObject jsonResponse = new JSONObject(response.toString());
                    final String status = jsonResponse.getString("status");
                    
                    runOnUiThread(new Runnable() {
                        @Override
                        public void run() {
                            Toast.makeText(BankingActivity.this, "Transfer " + status, Toast.LENGTH_LONG).show();
                        }
                    });
                    
                } catch (Exception e) {
                    e.printStackTrace();
                }
            }
        }).start();
    }
    
    public void saveUserCredentials(String accountNumber, String pin) {
        SharedPreferences.Editor editor = prefs.edit();
        editor.putString("account_number", accountNumber);
        editor.putString("user_pin", pin);
        editor.commit();
    }
}

